### Async Export Handling
```rust
// Export runs in background task
fn handle_export_action(&mut self) {
    let session = self.get_selected_session();
    let options = self.state.export_modal.as_ref().unwrap().to_options();

    // Spawn async task
    let (tx, rx) = tokio::sync::oneshot::channel();
    tokio::spawn(async move {
        let result = export_session_to_html(&session, &options).await;
        let _ = tx.send(result);
    });

    self.state.export_modal.as_mut().unwrap().export_state = ExportProgress::Preparing;
    self.pending_export = Some(rx);
}

// Poll for completion in update loop
fn poll_export(&mut self) {
    if let Some(ref mut rx) = self.pending_export {
        if let Ok(result) = rx.try_recv() {
            self.handle_export_result(result);
            self.pending_export = None;
        }
    }
}
```

## CLI Command Handler

### Handler Function
```rust
// In src/cli.rs
pub async fn handle_export_html(args: ExportHtmlArgs) -> Result<(), CliError> {
    // Load session
    let session = load_session(&args.session)?;

    // Build options from args
    let options = ExportOptions {
        output_dir: args.output_dir,
        filename: args.filename,
        encrypt: args.encrypt,
        password: get_password(&args)?,
        include_tools: args.include_tools,
        enable_cdns: !args.no_cdns,
        ..Default::default()
    };

    // Execute export
    let result = export_session_to_html(&session, &options).await?;

    // Output based on mode
    if args.robot {
        output_json(&ExportResponse::success(result))?;
    } else {
        println!("✓ Exported to {}", result.output_path.display());
        if args.open {
            open_in_browser(&result.output_path)?;
        }
    }

    Ok(())
}
```

### Open in Browser (--open flag)
```rust
fn open_in_browser(path: &Path) -> Result<(), CliError> {
    #[cfg(target_os = "macos")]
    std::process::Command::new("open").arg(path).spawn()?;

    #[cfg(target_os = "linux")]
    std::process::Command::new("xdg-open").arg(path).spawn()?;

    #[cfg(target_os = "windows")]
    std::process::Command::new("explorer").arg(path).spawn()?;

    Ok(())
}
```

## Progress Feedback

### TUI Progress Indicator
```rust
// Show spinner during export
fn render_export_progress(&self, frame: &mut Frame, area: Rect) {
    let progress = match self.state.export_modal.as_ref().unwrap().export_state {
        ExportProgress::Preparing => "Preparing export...",
        ExportProgress::Encrypting => "Encrypting content...",
        ExportProgress::Writing => "Writing file...",
        ExportProgress::Complete(_) => "Complete!",
        ExportProgress::Error(_) => "Error",
        _ => "Idle",
    };

    let spinner = Spinner::new(progress);
    frame.render_widget(spinner, area);
}
```

