## Error Handling

### TUI Error Display
```rust
fn handle_export_result(&mut self, result: Result<ExportResult, ExportError>) {
    match result {
        Ok(export) => {
            self.state.export_modal.as_mut().unwrap().export_state = 
                ExportProgress::Complete(export.output_path.clone());
            self.show_toast(&format!("Exported to {}", export.output_path.display()), ToastType::Success);
        }
        Err(e) => {
            self.state.export_modal.as_mut().unwrap().export_state = 
                ExportProgress::Error(e.to_string());
            self.show_toast(&format!("Export failed: {}", e), ToastType::Error);
        }
    }
}
```

### CLI Error Mapping
```rust
impl From<ExportError> for CliError {
    fn from(e: ExportError) -> Self {
        match e {
            ExportError::SessionNotFound(_) => CliError::new(3, "session_not_found", ...),
            ExportError::OutputDirNotWritable(_) => CliError::new(4, "output_not_writable", ...),
            ExportError::EncryptionFailed(_) => CliError::new(5, "encryption_error", ...),
            ExportError::PasswordRequired => CliError::new(6, "password_required", ...),
        }
    }
}
```

